-- Enrichment marathon batch: SeedDMS, SeekOut, Segment, Sejda PDF, Selfoss, Sellfy, Semaphore, Sematext

-- ── SeedDMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SeedDMS is a free, open-source, self-hosted document management system built in PHP that helps small and mid-sized organizations store, version, and control access to documents with configurable workflows.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Community-maintained open-source project, not a company; developed primarily by a single lead maintainer with volunteer contributors$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$Dutch$q$, $q$Portuguese$q$, $q$Russian$q$, $q$Polish$q$, $q$Czech$q$]::text[],
  seo_title = COALESCE($q$SeedDMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$SeedDMS is a free, open-source document management system for self-hosting. See its features, requirements, pricing (it is free), and how it compares to paid DMS tools.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SeedDMS is a free and open-source document management system (DMS) written in PHP, built for organizations that want to self-host document storage, versioning, and workflow control without paying software licensing fees. The project traces its lineage to myDMS, which began development around 2002 and was later renamed LetoDMS around 2008; in February 2013, lead developer Uwe Steinmann forked the codebase and renamed it SeedDMS after a dispute over the direction of the original project, and he has remained its primary maintainer ever since, with the project now in its second decade of active development. SeedDMS runs on Linux, macOS, and Windows, and supports MySQL, SQLite3, or PostgreSQL as its database backend, so it can be deployed on shared hosting, a private server, or a home lab with no per-user or per-document licensing limits. Its core feature set includes a fully web-based interface, storage of every document version with rollback, granular user and group permissions, external authentication support, configurable email notifications on document changes, and a workflow engine for review, approval, and revision cycles. SeedDMS also supports fulltext search, custom metadata fields and attributes, WebDAV access for drag-and-drop file management from a desktop client, and integrations with third-party tools such as Collabora Online, OnlyOffice, Tesseract OCR, Apache Tika, Etherpad, HedgeDoc, and Paperless-ngx for document conversion and collaborative editing. The interface has been translated into more than 20 languages through community contributions, including English, German, French, Spanish, Italian, Dutch, Portuguese, Russian, Polish, and Czech, though translation completeness varies since the project relies on volunteer submissions rather than professional localization. SeedDMS is released under the GNU General Public License version 2 (GPL v2), which means the source code is free to use, modify, and redistribute, including for commercial hosting. Because it is entirely free and open source, SeedDMS has no pricing tiers, subscription plans, or paywalled features anyone can download it and use it for unlimited users and documents, but there is no official vendor-provided support, hosting, or SLA; users rely on the SourceForge project page, community forums, and documentation for help. This makes SeedDMS best suited for technically capable teams, IT departments, small and mid-sized businesses, and privacy-conscious organizations that want full control over where their documents live and are comfortable managing their own server setup, backups, and updates. It is a reasonable lower-cost alternative to commercial document management platforms for organizations with tighter budgets or strict data-residency requirements, though it lacks the polished onboarding, official support contracts, and turnkey enterprise integrations that paid platforms typically offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '72dc4119-8718-45ec-8600-77edafd7ff89';

