-- ── SeekOut ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SeekOut is an AI-powered talent sourcing and recruiting platform that helps recruiters search over a billion candidate profiles, reach out with automated campaigns, and rediscover talent already in their ATS.$q$, short_description),
  pricing_model = COALESCE($q$Per-seat subscription with tiered and custom enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$From $149 per month (billed annually) for the Recruit Core plan$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees (previously larger before 2023-2024 workforce reductions)$q$, company_size),
  headquarters = COALESCE($q$Bellevue, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SeekOut Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$SeekOut is an AI recruiting and talent sourcing platform with access to 1B+ profiles. See 2026 pricing plans, key features, pros and cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SeekOut is an AI-powered talent sourcing and recruiting platform founded in 2017 by Anoop Gupta (CEO) and Aravind Bala (CTO), headquartered in Bellevue, Washington. The company has raised roughly $189 million in venture funding and was valued at approximately $1.2 billion at its peak, and it says it is used by more than 750 enterprises for recruiting. SeekOut's core product lets recruiters search across more than one billion candidate profiles aggregated from public and professional sources, apply more than 30 search filters (including diversity and skills-based filters), and launch AI-driven multi-step outreach campaigns integrated with email. Its platform has expanded from a pure sourcing tool into what it calls an agentic AI recruiting platform, adding capabilities like ATS rediscovery (surfacing past candidates already sitting in a company's applicant tracking system), inbound resume evaluation and AI screening, market intelligence reporting, and a managed service called SeekOut Spot that provides on-demand AI sourcing or AI recruiting-agency-style services billed per role rather than per seat. Pricing is tiered: the entry-level Recruit Core plan starts at $149 per month when billed annually (or $179 per month billed monthly) and includes unlimited search, 500 monthly contact credits, 1,000 monthly exports, and AI campaign tools, aimed at solo recruiters or small teams. Higher tiers Sourcing, Sourcing plus Integration, and Full Recruiting Funnel are sold at custom per-seat pricing billed annually, adding features like ATS rediscovery, SSO, advanced diversity filters, dedicated customer success, and white-glove implementation as the tier increases; real-world negotiated enterprise contracts have been reported in the range of roughly $3,000 to $10,000 per seat per year depending on volume and features. Enterprise buyers typically pay anywhere from around $1,200 to $1,999 or more per month for broader team deployments, and larger multi-seat contracts require a custom quote from SeekOut's sales team. SeekOut competes directly with LinkedIn Recruiter, hireEZ, and Gem in the talent sourcing category, and it differentiates on the breadth of its candidate database, diversity-focused search filters, and increasingly on agentic AI workflows that automate parts of sourcing and initial screening. The company underwent notable workforce reductions in late 2023 and again in mid-2024 (cutting around 30 percent of staff in the second round) as part of a broader downturn in HR tech spending, which has since narrowed its headcount from earlier peaks even as the product itself continued to expand into new AI-driven capabilities.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b3d5a700-1eb4-4e5e-b5cd-3a7dc302fad1';

