-- ── Sejda PDF ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sejda PDF is a browser-based and desktop PDF editor that lets users edit text and images, merge and split files, fill and sign forms, run OCR, and convert PDFs, with a limited free tier and paid plans for heavier use.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription (free tier with daily task limits, paid weekly, monthly, and annual plans)$q$, pricing_model),
  starting_price = COALESCE($q$Free with daily task limits; paid plans start around EUR 5.50 for a 7-day Web Week Pass$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Small company, exact headcount not publicly disclosed (estimated under 50 employees)$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands (operated by Sejda B.V.)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sejda PDF Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Sejda PDF is a browser and desktop PDF editor. See 2026 pricing plans, free tier limits, key features like OCR and e-signatures, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sejda PDF is a PDF editing tool that started in 2010 as an online project and is now operated by Sejda B.V., a company headquartered in Amsterdam, the Netherlands. It offers two main products: Sejda Web, a browser-based tool usable on any operating system without installation, and Sejda Desktop, a downloadable application for Windows, macOS, and Linux. The platform provides more than 30 individual PDF tools covering editing text and images directly inside a PDF, adding annotations and watermarks, merging and splitting files, rotating and reordering pages, converting to and from PDF (including Word, Excel, and image formats), filling and generating forms, applying electronic signatures, running optical character recognition (OCR) to make scanned documents searchable, setting access permissions and passwords, and batch-processing multiple files at once; some plans also expose API access for developers who want to integrate Sejda's PDF processing into their own applications. The free plan is usable without an account but is capped at a small number of tasks per day (commonly cited as around three), smaller file size limits, and restricted access to certain premium tools, which pushes frequent users toward a paid plan. Paid pricing is denominated in euros and structured around three main plans: a non-recurring Web Week Pass priced at 5.50 euros per user for seven days of full Sejda Web access, a recurring Web Monthly plan at 8.50 euros per user per month for ongoing browser-based access, and a Desktop+Web Annual plan at 71 euros per user per year that bundles a year of both the desktop application and web access at roughly a 30 percent discount versus paying monthly; a volume discount of 20 percent is available for organizations buying 10 or more user licenses. All paid tiers include unlimited documents, OCR support for up to 100 pages per task, batch processing, longer task-processing time allowances (up to about 21 minutes for large jobs), and larger file uploads up to 500MB, compared to the more restrictive free tier. Sejda targets a broad mix of freelancers, small businesses, and mid-size and large enterprises who need occasional to moderate PDF editing without adopting a heavier, more expensive suite like Adobe Acrobat, and it markets itself on simplicity, browser accessibility, and privacy, including automatic deletion of uploaded files from its servers after a short retention window. The tool draws significant organic traffic as a search-driven utility site, and it competes with other lightweight PDF editors such as PDFescape, Smallpdf, and iLovePDF in the crowded browser-based PDF tooling category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e533002d-957b-4a75-967f-c0c9aa3c3fc4';

