-- ── Selfoss ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Selfoss is a free, open-source, self-hosted PHP web application for aggregating RSS feeds, social media, and other content sources into a single, mobile-friendly reading interface.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Community-maintained open-source project, not a company$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Selfoss Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Selfoss is a free, open-source, self-hosted RSS reader and content aggregator. See its features, setup requirements, pricing (it is free), and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Selfoss is a free, open-source, self-hosted RSS reader and multi-source content aggregator originally created by developer Tobias Zeising, with its first public commit dating to October 2011. Written in PHP, Selfoss is designed to be lightweight, with an installed footprint of roughly 25MB, and it can be deployed on virtually any web host or home server that supports PHP and one of its supported databases, which include MySQL, PostgreSQL, and SQLite. Rather than being limited to RSS and Atom feeds alone, Selfoss functions as a general-purpose content mashup tool: through its open plugin system, developers and users can write custom data connectors to pull in content from social networks and other web sources, combining everything into a single unified reading timeline. The interface uses an adaptive, mobile-friendly layout that works on phones and tablets as well as desktop browsers, and feeds can be organized into categories and bulk-imported using standard OPML subscription files, making migration from other feed readers straightforward. Selfoss exposes a RESTful JSON API, which has enabled a small ecosystem of third-party and community-built mobile apps and browser extensions to interact with a self-hosted instance beyond its built-in web interface. Because feed content needs to be refreshed periodically, Selfoss relies on a scheduled job, either an HTTP-triggered endpoint or a command-line invocation run via cron or a systemd timer, to fetch new items from subscribed sources rather than polling continuously in the background. The project is released under the GNU General Public License version 3 (GPL-3.0) or, at the user's option, any later version, which permits free personal and commercial use, including operating a hosted instance for others, as long as modifications and distributions remain open source under the same license terms. After its original creator stepped back from active involvement, the project has continued to be maintained by community contributors, notably Jan Tojnar, in their free time, which is typical of small self-hosted open-source utilities. Selfoss has no company behind it, no pricing tiers, and no official support contracts; it is popular within the self-hosting and home-lab community, frequently appearing on curated lists of self-hosted applications alongside tools like FreshRSS, Miniflux, and Tiny Tiny RSS, and it is commonly deployed via Docker for ease of setup. It appeals specifically to technically inclined users who want full ownership of their reading data and RSS subscriptions rather than relying on a third-party cloud reading service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c279c42d-acd3-443e-8e69-69c91b4a2455';

