-- ── Semaphore ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Semaphore (Semaphore CI) is a cloud-native continuous integration and continuous delivery (CI/CD) platform that runs code builds, tests, and deployments with per-second usage-based pricing and a free monthly credit tier.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based pay-as-you-go pricing (billed per minute of compute) with a monthly free credit allowance and paid support add-ons; free Enterprise Edition for qualifying smaller companies$q$, pricing_model),
  starting_price = COALESCE($q$Free tier includes $15 of monthly usage credit; usage billed from $0.0025 per minute for self-hosted agents$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$11-50 employees (Rendered Text, the company behind Semaphore, has approximately 46 employees)$q$, company_size),
  headquarters = COALESCE($q$Novi Sad, Serbia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Semaphore CI/CD Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Semaphore (Semaphore CI) is a cloud-native CI/CD platform. See 2026 usage-based pricing, key features, pros and cons, and alternatives like GitHub Actions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Semaphore, commonly known as Semaphore CI, is a cloud-native continuous integration and continuous delivery (CI/CD) platform built by Rendered Text, a software company founded in 2009 by Marko Anastasov and Darko Fabijan and headquartered in Novi Sad, Serbia. The Semaphore product itself launched publicly in March 2012, making it one of the longer-running hosted CI platforms still actively developed today. Rendered Text, the company behind it, operates with a relatively small team of roughly 46 employees as of recent reporting, and the company has said Semaphore is used by more than 300,000 organizations globally, ranging from startups to Fortune 500 companies, with SOC 2 and ISO 27001 certifications supporting its enterprise credibility. Semaphore lets teams define pipelines that build, test, and deploy code automatically on every commit or pull request, running jobs on Ubuntu (x86 and ARM), macOS, or self-hosted agents, with support for parallelized test execution, Docker layer caching, and deployment automation to common cloud targets. Pricing on Semaphore's cloud (SaaS) platform is usage-based and billed per second of compute time rather than per seat: every account receives 15 dollars of free usage credit each month, equivalent to roughly 2,000 minutes on a standard 2-vCPU Ubuntu x64 machine, along with 20 concurrent jobs, 20GB of monthly egress, and 100GB of monthly storage by default. Beyond the free credit, compute is billed per minute at rates that vary by machine type for example, Ubuntu ARM machines start around 0.003 dollars per minute for a 2-vCPU instance, Ubuntu x64 machines start around 0.0075 dollars per minute, macOS machines run about 0.09 dollars per minute for a 4-vCPU instance, and self-hosted agents are billed at a flat 0.0025 dollars per minute regardless of machine type. There are no per-seat license fees and no charge for idle time, since teams only pay for compute actually consumed running pipelines. For teams that want faster or more hands-on support, Semaphore sells optional monthly add-ons layered on top of usage pricing, including Basic support at 50 dollars per month, Priority Response support at 250 dollars per month, and higher-tier SLA plans at 500 and 750 dollars per month, plus separate paid customer success and engineering-hours packages for teams that want migration help or performance tuning. Notably, Semaphore introduced a new enterprise pricing approach in 2025 that makes its self-hosted Enterprise Edition completely free for companies with under 5 million dollars in annual revenue and up to 50 users, alongside a guarantee of at least 50 percent lower CI/CD spend compared to a customer's existing setup on its hosted SaaS platform, with migration support included. Semaphore competes in the CI/CD space with GitHub Actions, CircleCI, GitLab CI/CD, and Buildkite, and it differentiates primarily on raw pipeline execution speed, per-second granular billing with no idle costs, and increasingly generous terms for smaller companies through its free Enterprise Edition offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '32135d16-f5f2-4da3-94f9-bb49145ae75e';

